update course_schedule
teacher_id = #{teacherId}, classroom_id = #{classroomId}, week_day = #{weekDay}, start_section = #{startSection}, end_section = #{endSection}, week_range = #{weekRange},
where id = #{id}

mapper.select:
select cs.id, cs.semester_id, s.name as semester_name, cs.course_id, c.course_name, t.id as teacher_id, t.name as teacher_name,
       cr.id as classroom_id, CONCAT(cr.building, cr.room_number) as classroom_name,
       (select GROUP_CONCAT(cl.class_name separator '、')
        from course_schedule_class csc
        join class cl on csc.class_id = cl.id
        where csc.schedule_id = cs.id) as classNames,
       cs.week_day, cs.start_section, cs.end_section, cs.week_range
from course_schedule cs
left join semester s on cs.semester_id = s.id
left join course c on cs.course_id = c.id
left join teacher t on cs.teacher_id = t.id
left join classroom cr on cs.classroom_id = cr.id

    cs.semester_id = #{semesterId}
    and cs.course_id = #{courseId}
    and cs.teacher_id = #{teacherId}
    and cs.classroom_id = #{classroomId}
    and cs.week_day = #{weekDay}

        and CAST(SUBSTRING_INDEX(cs.week_range, '-', 1) AS UNSIGNED) <= #{weekNum}
        and CAST(SUBSTRING_INDEX(cs.week_range, '-', -1) AS UNSIGNED) >= #{weekNum}

select cs.id as course_schedule_id, c.course_name, t.name as teacher_name, CONCAT(cr.building, cr.room_number) as classroom_name, (select GROUP_CONCAT(cl.class_name separator '、') from course_schedule_class csc join class cl on csc.class_id = cl.id where csc.schedule_id = cs.id) as classNames, cs.week_day, cs.start_section, cs.end_section, cs.week_range from course_schedule cs left join course c on cs.course_id = c.id left join teacher t on cs.teacher_id = t.id left join classroom cr on cs.classroom_id = cr.id
cs.semester_id = #{semesterId} and cs.teacher_id = #{userId}
and exists ( select 1 from course_schedule_class csc where csc.schedule_id = cs.id and csc.class_id in
#{classId}
)
order by cs.week_day asc, cs.start_section asc

select cs.course_id as courseId, c.course_name as courseName, c.credit, t.name as teacherName, CONCAT(cr.building, cr.room_number) as classroomName, cs.week_day as weekDay, cs.start_section as startSection, cs.end_section as endSection, cs.week_range as weekRange from course_schedule cs left join course c on cs.course_id = c.id left join teacher t on cs.teacher_id = t.id left join classroom cr on cs.classroom_id = cr.id where cs.semester_id = #{semesterId} and exists ( select 1 from course_schedule_class csc where csc.schedule_id = cs.id and csc.class_id in
#{classId}
) order by cs.week_day asc, cs.start_section asc

select cs.id, cs.semester_id, s.name as semester_name, cs.course_id, c.course_name, t.id as teacher_id, t.name as teacher_name,
       cr.id as classroom_id, CONCAT(cr.building, cr.room_number) as classroom_name, cs.week_day, cs.start_section, cs.end_section, cs.week_range,
       cs.create_time as createTime, cs.update_time as updateTime
from course_schedule cs
left join semester s on cs.semester_id = s.id
left join course c on cs.course_id = c.id
left join teacher t on cs.teacher_id = t.id
left join classroom cr on cs.classroom_id = cr.id
where cs.semester_id = #{semesterId}
and cs.teacher_id = #{teacherId}
and cs.week_day = #{weekDay}
and not (cs.end_section < #{startSection} or cs.start_section > #{endSection})
and cs.id != #{excludeId}

